#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;

int dp[50005], v[50005];

int main(){
	int t, m;
	cin >> t >> m;
	for(int i = 1; i <= m; i++)
	    cin >> v[i];
	for(int i = 1; i <= t; i++)
	    dp[i] = 0;
	for(int i = 1; i <= m; i++)
	    for(int j = t; j >= v[i]; j--)
	        dp[j] = max(dp[j - v[i]] + v[i], dp[j]);
	cout << dp[t];
	return 0;
}
